<template>
  <div>
    <HeroHeaderDashboard :title="title" :breadcrumbs="breadcrumbs" />
    <BoxContent>
      <template #content>
        <BoxInformation title="Editar categoría" :columns="1">
          <FormCategory :category="category" @saved="handleCategorySaved" />
        </BoxInformation>
      </template>
      <template #sidebar>
        <BoxInformation title="Detalles" :columns="1">
          <CardInfoDashboard
            v-if="category"
            title="Fecha de creación"
            :description="formatDate(category.createdAt)"
          />
          <CardInfoDashboard
            v-if="category"
            title="Última modificación"
            :description="formatDate(category.updatedAt)"
          />
        </BoxInformation>
      </template>
    </BoxContent>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from "vue";
import { useRoute } from "vue-router";
import FormCategory from "@/components/FormCategory.vue";
import type { CategoryData } from "@/components/FormCategory.vue";
import { formatDate } from "@/utils/date";

interface CategoryRecord extends CategoryData {
  createdAt?: string;
  updatedAt?: string;
}

definePageMeta({
  layout: "dashboard",
});

const route = useRoute();
const category = ref<CategoryRecord | null>(null);
const apiClient = useApiClient();

const title = computed(() => category.value?.name || "Categoría");
const breadcrumbs = computed(() => [
  { label: "Categorías", to: "/dashboard/maintenance/categories" },
  ...(category.value?.name
    ? [
        {
          label: category.value.name,
          to: `/dashboard/maintenance/categories/${route.params.id}`,
        },
      ]
    : []),
  { label: "Editar" },
]);

const handleCategorySaved = (updatedCategory: CategoryData) => {
  if (updatedCategory) {
    category.value = updatedCategory;
  }
};

const { data: categoryData } = await useAsyncData(
  `category-edit-${route.params.id}`,
  async () => {
    const id = route.params.id;
    if (!id) return null;

    const response = (await apiClient("categories", {
      method: "GET",
      params: {
        filters: { documentId: { $eq: id } },
        populate: ["icon"],
      } as unknown as Record<string, unknown>,
    })) as { data: unknown[] };
    const data = Array.isArray(response.data) ? response.data[0] : null;
    if (data) return data;

    const fallback = (await apiClient(`categories/${id}`, {
      method: "GET",
      params: { populate: ["icon"] } as unknown as Record<string, unknown>,
    })) as { data: unknown };
    return (fallback.data as unknown) || null;
  },
);

category.value = categoryData.value ?? null;
</script>
